"use client";

import React, { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Quote } from "@/lib/types";
import { getRandomQuote, getRandomQuotes } from "@/lib/api/quotable";
import { QuoteCard } from "@/components/ui/QuoteCard";
import { QuoteCardSkeleton } from "@/components/ui/Skeleton";
import { RefreshCw, Sparkles, Wand2 } from "lucide-react";

export default function HomePage() {
  const [mainQuote, setMainQuote] = useState<Quote | null>(null);
  const [suggestions, setSuggestions] = useState<Quote[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchQuotes = useCallback(async (tag?: string) => {
    try {
      setRefreshing(true);
      setError(null);
      
      // Fetch main quote and suggestions in parallel
      const [quote, moreLikeThis] = await Promise.all([
        getRandomQuote(tag),
        getRandomQuotes(3, tag),
      ]);
      
      setMainQuote(quote);
      // Filter out the main quote from suggestions
      setSuggestions(moreLikeThis.filter((q) => q._id !== quote._id).slice(0, 3));
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to load quotes. Please try again."
      );
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  // Initial fetch
  useEffect(() => {
    fetchQuotes();
  }, [fetchQuotes]);

  // Keyboard shortcut: "R" to refresh
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "r" && !e.ctrlKey && !e.metaKey && document.activeElement?.tagName !== "INPUT") {
        e.preventDefault();
        fetchQuotes(mainQuote?.tags[0]);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [fetchQuotes, mainQuote]);

  const handleRefresh = () => {
    fetchQuotes();
  };

  const handleMoreLikeThis = (tag: string) => {
    fetchQuotes(tag);
  };

  if (error) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-16">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center"
        >
          <div className="inline-flex items-center justify-center w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full mb-4">
            <span className="text-2xl">😢</span>
          </div>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-2">
            Oops! Something went wrong
          </h2>
          <p className="text-gray-600 dark:text-gray-400 mb-6">{error}</p>
          <button
            onClick={handleRefresh}
            className="inline-flex items-center gap-2 px-6 py-3 bg-primary-500 hover:bg-primary-600 text-white rounded-xl font-medium transition-colors"
          >
            <RefreshCw className="w-4 h-4" />
            Try Again
          </button>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
      {/* Hero Section */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-center mb-12"
      >
        <h1 className="text-4xl sm:text-5xl font-bold mb-4">
          <span className="bg-gradient-to-r from-primary-600 via-accent-500 to-primary-600 dark:from-primary-400 dark:via-accent-400 dark:to-primary-400 bg-clip-text text-transparent">
            Daily Inspiration
          </span>
        </h1>
        <p className="text-gray-600 dark:text-gray-400 text-lg max-w-xl mx-auto">
          Discover wisdom from great minds. Like your favorites, share with friends.
        </p>
      </motion.div>

      {/* Main Quote */}
      <section className="mb-12">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <Sparkles className="w-5 h-5 text-primary-500" />
            <h2 className="text-lg font-semibold text-gray-900 dark:text-gray-100">
              Quote of the Moment
            </h2>
          </div>
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={handleRefresh}
            disabled={refreshing}
            className="flex items-center gap-2 px-4 py-2 bg-primary-100 dark:bg-primary-900/30 text-primary-600 dark:text-primary-400 rounded-lg font-medium hover:bg-primary-200 dark:hover:bg-primary-800/50 transition-colors disabled:opacity-50"
          >
            <RefreshCw className={`w-4 h-4 ${refreshing ? "animate-spin" : ""}`} />
            <span className="hidden sm:inline">New Quote</span>
            <kbd className="hidden sm:inline-flex ml-1 px-1.5 py-0.5 text-xs bg-primary-200 dark:bg-primary-800 rounded">
              R
            </kbd>
          </motion.button>
        </div>

        <AnimatePresence mode="wait">
          {loading ? (
            <QuoteCardSkeleton key="skeleton" />
          ) : mainQuote ? (
            <QuoteCard key={mainQuote._id} quote={mainQuote} />
          ) : null}
        </AnimatePresence>

        {/* Tag-based "More Like This" buttons */}
        {mainQuote && mainQuote.tags.length > 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
            className="mt-6 flex flex-wrap items-center gap-2"
          >
            <span className="text-sm text-gray-500 dark:text-gray-400 flex items-center gap-1">
              <Wand2 className="w-4 h-4" />
              More like this:
            </span>
            {mainQuote.tags.slice(0, 4).map((tag) => (
              <button
                key={tag}
                onClick={() => handleMoreLikeThis(tag)}
                className="px-3 py-1.5 text-sm bg-gray-100 dark:bg-gray-800 hover:bg-primary-100 dark:hover:bg-primary-900/30 text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 rounded-full transition-colors"
              >
                {tag}
              </button>
            ))}
          </motion.div>
        )}
      </section>

      {/* Suggestions */}
      {suggestions.length > 0 && (
        <motion.section
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
        >
          <h2 className="text-lg font-semibold text-gray-900 dark:text-gray-100 mb-6 flex items-center gap-2">
            <span className="w-1.5 h-6 bg-gradient-to-b from-primary-500 to-accent-500 rounded-full" />
            You Might Also Like
          </h2>
          <div className="grid gap-6">
            {suggestions.map((quote, index) => (
              <QuoteCard
                key={quote._id}
                quote={quote}
                showFullMeta={false}
                animationDelay={index * 0.1}
              />
            ))}
          </div>
        </motion.section>
      )}

      {/* Keyboard Shortcuts Info */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.6 }}
        className="mt-12 text-center text-sm text-gray-400 dark:text-gray-600"
      >
        <p>
          Press <kbd className="px-1.5 py-0.5 bg-gray-100 dark:bg-gray-800 rounded">R</kbd> for a new quote
          {" · "}
          <kbd className="px-1.5 py-0.5 bg-gray-100 dark:bg-gray-800 rounded">/</kbd> to search
        </p>
      </motion.div>
    </div>
  );
}
