"use client";

import React from "react";
import { motion } from "framer-motion";

export function QuoteCardSkeleton() {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-6 md:p-8 border border-gray-100 dark:border-gray-700"
    >
      {/* Quote Icon Skeleton */}
      <div className="absolute -top-4 left-6 w-11 h-11 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse" />

      {/* Quote Content Skeleton */}
      <div className="mt-4 mb-6 space-y-3">
        <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse" />
        <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse w-5/6" />
        <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse w-4/6" />
      </div>

      {/* Author Skeleton */}
      <div className="flex items-center justify-between">
        <div className="h-5 w-32 bg-gray-200 dark:bg-gray-700 rounded animate-pulse" />
        <div className="flex gap-2">
          <div className="w-9 h-9 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse" />
          <div className="w-9 h-9 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse" />
        </div>
      </div>

      {/* Tags Skeleton */}
      <div className="mt-4 pt-4 border-t border-gray-100 dark:border-gray-700">
        <div className="flex gap-2">
          <div className="h-6 w-16 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse" />
          <div className="h-6 w-20 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse" />
        </div>
      </div>
    </motion.div>
  );
}

export function QuoteListSkeleton({ count = 3 }: { count?: number }) {
  return (
    <div className="space-y-6">
      {Array.from({ length: count }).map((_, i) => (
        <QuoteCardSkeleton key={i} />
      ))}
    </div>
  );
}

export function AuthorCardSkeleton() {
  return (
    <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 border border-gray-100 dark:border-gray-700">
      <div className="flex items-start gap-6">
        {/* Avatar Skeleton */}
        <div className="w-24 h-24 bg-gray-200 dark:bg-gray-700 rounded-full animate-pulse flex-shrink-0" />
        
        <div className="flex-1 space-y-3">
          {/* Name Skeleton */}
          <div className="h-8 w-48 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse" />
          
          {/* Description Skeleton */}
          <div className="h-5 w-32 bg-gray-200 dark:bg-gray-700 rounded animate-pulse" />
          
          {/* Bio Skeleton */}
          <div className="space-y-2 pt-2">
            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded animate-pulse" />
            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded animate-pulse w-5/6" />
            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded animate-pulse w-4/6" />
          </div>
        </div>
      </div>
    </div>
  );
}
